using System;

class Program
{
    const double Pi = 3.14159;

    static void Main(string[] args)
    {
        const int MaxAttempts = 3;
        Console.WriteLine($"Pi dəyəri: {Pi}");
        Console.WriteLine($"Maksimum cəhd sayı: {MaxAttempts}");
        // Pi = 3.14; // Xəta: const dəyəri dəyişdirilə bilməz
    }
}
// Output:
// Pi dəyəri: 3.14159
// Maksimum cəhd sayı: 3

using System;

class Program
{
    readonly int CreationYear;

    public Program()
    {
        CreationYear = 2025;
    }

    static void Main(string[] args)
    {
        Program program = new Program();
        Console.WriteLine($"Yaradılma ili: {program.CreationYear}");
        // program.CreationYear = 2026; // Xəta: readonly dəyəri dəyişdirilə bilməz
    }
}
// Output:
// Yaradılma ili: 2025

using System;

class Circle
{
    const double Pi = 3.14159;
    readonly double Radius;

    public Circle(double radius)
    {
        Radius = radius;
    }

    public double CalculateArea()
    {
        return Pi * Radius * Radius;
    }

    static void Main(string[] args)
    {
        Circle circle = new Circle(5.0);
        Console.WriteLine($"Dairənin sahəsi: {circle.CalculateArea()}");
    }
}
// Output:
// Dairənin sahəsi: 78.53975

